Here is an example of implementing a stack using a `std::vector` in C++:

```cpp
#include <iostream>
#include <vector>

template <typename T>
class Stack {
private:
    std::vector<T> elements;
public:
    void push(const T& element) {
        elements.push_back(element);
    }

    void pop() {
        if (!elements.empty()) {
            elements.pop_back();
        }
    }

    T top() {
        if (!elements.empty()) {
            return elements.back();
        }
        throw std::out_of_range("Stack is empty");
    }

    bool empty() {
        return elements.empty();
    }
};

int main() {
    Stack<int> mystack;

    mystack.push(1);
    mystack.push(2);
    mystack.push(3);

    std::cout << mystack.top() << std::endl; // Output: 3
    mystack.pop();
    std::cout << mystack.top() << std::endl; // Output: 2

    return 0;
}
```

In this example, we use `std::vector` to store the elements in the stack. The `push`, `pop`, `top`, and `empty` methods are implemented for the stack class.

